namespace sv_af69ba0da6804911966615c51a371c7f.Services;

public class CartItem
{
    public int Id { get; set; }
    public string Name { get; set; } = "";
    public decimal Price { get; set; }
    public int Quantity { get; set; }
}

namespace sv_af69ba0da6804911966615c51a371c7f.Services;

public class CartState
{
    private readonly List<CartItem> _items = new();
    private readonly Lock _lock = new();

    public event Action? OnChange;

    public IReadOnlyList<CartItem> Items
    {
        get { lock (_lock) { return _items.ToList(); } }
    }

    public int TotalCount
    {
        get { lock (_lock) { return _items.Sum(i => i.Quantity); } }
    }

    public decimal TotalPrice
    {
        get { lock (_lock) { return _items.Sum(i => i.Price * i.Quantity); } }
    }

    public void Add(CartItem item)
    {
        lock (_lock)
        {
            var existing = _items.FirstOrDefault(i => i.Id == item.Id);
            if (existing is not null)
            {
                existing.Quantity += item.Quantity;
            }
            else
            {
                _items.Add(new CartItem
                {
                    Id = item.Id,
                    Name = item.Name,
                    Price = item.Price,
                    Quantity = item.Quantity
                });
            }
        }
        OnChange?.Invoke();
    }

    public void Remove(int id)
    {
        lock (_lock)
        {
            _items.RemoveAll(i => i.Id == id);
        }
        OnChange?.Invoke();
    }

    public void Clear()
    {
        lock (_lock)
        {
            _items.Clear();
        }
        OnChange?.Invoke();
    }
}

using System.Collections.Concurrent;

namespace sv_af69ba0da6804911966615c51a371c7f.Services;

/// <summary>
/// Singleton service that holds per-session cart state.
/// Each user gets an independent CartState keyed by their session cookie.
/// </summary>
public class CartStore
{
    private readonly ConcurrentDictionary<string, CartState> _carts = new();

    public CartState GetCart(string sessionId)
    {
        return _carts.GetOrAdd(sessionId, _ => new CartState());
    }
}

