using sv_af69ba0da6804911966615c51a371c7f.Components;
using sv_af69ba0da6804911966615c51a371c7f.Services;

var builder = WebApplication.CreateBuilder(args);

// Add services to the container.
builder.Services.AddRazorComponents()
    .AddInteractiveServerComponents();
builder.Services.AddSingleton<CartStore>();

var app = builder.Build();

// Configure the HTTP request pipeline.
if (!app.Environment.IsDevelopment())
{
    app.UseExceptionHandler("/Error", createScopeForErrors: true);
}
app.UseStatusCodePagesWithReExecute("/not-found", createScopeForStatusCodePages: true);

// Assign a cart session cookie so each user gets an independent cart.
app.Use(async (context, next) =>
{
    if (!context.Request.Cookies.ContainsKey("CartSessionId"))
    {
        context.Response.Cookies.Append("CartSessionId", Guid.NewGuid().ToString(), new CookieOptions
        {
            HttpOnly = true,
            SameSite = SameSiteMode.Strict,
            Expires = DateTimeOffset.UtcNow.AddDays(30)
        });
    }
    await next();
});

app.UseAntiforgery();

