@page "/products"
@rendermode InteractiveServer
@inject Services.CartStore CartStore

<PageTitle>Products</PageTitle>

<h1>Products</h1>

<div class="row row-cols-1 row-cols-md-3 g-4">
    @foreach (var product in _products)
    {
        <div class="col">
            <div class="card h-100">
                <div class="card-body">
                    <h5 class="card-title">@product.Name</h5>
                    <p class="card-text">@product.Price.ToString("C")</p>
                    <button class="btn btn-primary" @onclick="() => AddToCart(product)">
                        Add to Cart
                    </button>
                </div>
            </div>
        </div>
    }
</div>

@code {
    [CascadingParameter(Name = "CartSessionId")]
    public string SessionId { get; set; } = "";

    private Services.CartState? _cart;

    private readonly List<ProductInfo> _products =
    [
        new(1, "Wireless Headphones", 59.99m),
        new(2, "Mechanical Keyboard", 89.99m),
        new(3, "USB-C Hub", 34.99m),
        new(4, "Monitor Stand", 45.99m),
        new(5, "Webcam HD", 74.99m),
        new(6, "Mouse Pad XL", 19.99m),
    ];

    protected override void OnInitialized()
    {
        if (!string.IsNullOrEmpty(SessionId))
            _cart = CartStore.GetCart(SessionId);
    }

    private void AddToCart(ProductInfo product)
    {
        _cart?.Add(new Services.CartItem
        {
            Id = product.Id,
            Name = product.Name,
            Price = product.Price,
            Quantity = 1
        });
    }

    private record ProductInfo(int Id, string Name, decimal Price);
}

@page "/cart"
@rendermode InteractiveServer
@inject Services.CartStore CartStore
@implements IDisposable

<PageTitle>Cart</PageTitle>

<h1>Your Cart</h1>

@if (_cart is null || !_cart.Items.Any())
{
    <p>Your cart is empty.</p>
}
else
{
    <table class="table">
        <thead>
            <tr>
                <th>Product</th>
                <th>Price</th>
                <th>Quantity</th>
                <th>Subtotal</th>
                <th></th>
            </tr>
        </thead>
        <tbody>
            @foreach (var item in _cart.Items)
            {
                <tr>
                    <td>@item.Name</td>
                    <td>@item.Price.ToString("C")</td>
                    <td>@item.Quantity</td>
                    <td>@((item.Price * item.Quantity).ToString("C"))</td>
                    <td>
                        <button class="btn btn-danger btn-sm" @onclick="() => Remove(item.Id)">
                            Remove
                        </button>
                    </td>
                </tr>
            }
        </tbody>
        <tfoot>
            <tr>
                <td colspan="3"><strong>Total</strong></td>
                <td><strong>@_cart.TotalPrice.ToString("C")</strong></td>
                <td>
                    <button class="btn btn-outline-danger btn-sm" @onclick="ClearCart">
                        Clear All
                    </button>
                </td>
            </tr>
        </tfoot>
    </table>
}

@code {
    [CascadingParameter(Name = "CartSessionId")]
    public string SessionId { get; set; } = "";

    private Services.CartState? _cart;

    protected override void OnInitialized()
    {
        if (!string.IsNullOrEmpty(SessionId))
        {
            _cart = CartStore.GetCart(SessionId);
            _cart.OnChange += OnCartChanged;
        }
    }

    private void Remove(int id) => _cart?.Remove(id);

    private void ClearCart() => _cart?.Clear();

    private void OnCartChanged()
    {
        InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        if (_cart is not null)
            _cart.OnChange -= OnCartChanged;
    }
}
